#!/usr/bin/env python3
"""Update the 6 Literary Scrimmage map icons inside assets/assets.json.
Run once from your repo root:   python3 apply_icons.py
It backs up assets.json to assets.json.bak, replaces ONLY the six icon
entries (a111-a116), leaves every other asset untouched, and refreshes
manifest.json if present. Safe to re-run.
"""
import json, os, sys, hashlib

HERE = os.path.dirname(os.path.abspath(__file__))
ASSETS = os.path.join(HERE, "assets", "assets.json")
MANIFEST = os.path.join(HERE, "manifest.json")

LABELS = {
"a111": "archives (Study Break)",
"a112": "rest (Coffee Break)",
"a113": "start (Start)",
"a114": "scrim (Scrimmage)",
"a115": "elite (Thesis Defense)",
"a116": "boss (Algorithm Boss)"
}

NEW = {
  "a111": "",
  "a112": "",
  "a113": "",
  "a114": "",
  "a115": "",
  "a116": "",
}

def main():
    if not os.path.exists(ASSETS):
        sys.exit(f"[icons] ERROR: {ASSETS} not found. Run this from your repo root.")
    assets = json.load(open(ASSETS))
    missing = [k for k in NEW if k not in assets]
    if missing:
        sys.exit(f"[icons] ERROR: expected ids not in bundle: {missing}")
    # backup once
    bak = ASSETS + ".bak"
    if not os.path.exists(bak):
        json.dump(assets, open(bak, "w"), separators=(",", ":"))
        print(f"[icons] backup written: {bak}")
    for aid, b64 in NEW.items():
        old = assets[aid]; assets[aid] = b64
        tag = "unchanged" if old == b64 else "updated"
        print(f"[icons] {aid}  {LABELS.get(aid, aid):26s} {tag}  ({len(b64)} b64 chars)")
    json.dump(assets, open(ASSETS, "w"), separators=(",", ":"))
    print(f"[icons] wrote {ASSETS}")
    # refresh manifest (optional, best-effort)
    if os.path.exists(MANIFEST):
        try:
            man = json.load(open(MANIFEST))
            for rec in man.get("assets", []):
                if rec.get("id") in NEW:
                    b64 = NEW[rec["id"]]
                    rec["media_type"] = "image/png"
                    rec["bytes_b64"] = len(b64)
                    rec["sha256"] = hashlib.sha256(b64.encode()).hexdigest()
            json.dump(man, open(MANIFEST, "w"), indent=1)
            print(f"[icons] manifest.json refreshed")
        except Exception as e:
            print(f"[icons] (manifest refresh skipped: {e})")
    print("\n[icons] Done. Next:  python3 build.py   then open dist/academic_battle_cards.html")

if __name__ == "__main__":
    main()
